// -- Design tokens -----------------------------------------------------------
const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  textMuted: tokens.color.textMuted, green: tokens.color.green, red: tokens.color.red,
  blue: tokens.color.blue, amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
};
const mono = tokens.font.mono;
const body = tokens.font.sans;

// -- Helpers -----------------------------------------------------------------
function fmtDollar(v) {
  if (v == null || !isFinite(v)) return '--';
  if (Math.abs(v) >= 1e6) return `$${(v / 1e6).toFixed(1)}M`;
  if (Math.abs(v) >= 1e3) return `$${(v / 1e3).toFixed(1)}K`;
  return `$${Math.round(v).toLocaleString()}`;
}
function fmtPct(v, d = 1) {
  if (v == null || !isFinite(v)) return '--';
  return `${Number(v).toFixed(d)}%`;
}
function fmtDate(iso) {
  if (!iso) return '--';
  try {
    const d = new Date(iso);
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  } catch { return iso; }
}
function timeAgo(iso) {
  if (!iso) return '';
  try {
    const d = new Date(iso);
    const now = Date.now();
    const diff = now - d.getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    const days = Math.floor(hrs / 24);
    return `${days}d ago`;
  } catch { return ''; }
}
function formatStrategyLabel(key) {
  if (!key) return '';
  return key.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
}

// -- Glass Panel -------------------------------------------------------------
function GlassPanel({ children, className, style }) {
  return (
    <div className={`${s.glassPanel} ${className || ''}`} style={style}>
      {children}
    </div>
  );
}

// -- Copy button (reusable) --------------------------------------------------
function CopyButton({ text, label = 'Copy Link' }) {
  const [copied, setCopied] = useState(false);
  const copyToClipboard = async () => {
    try {
      await navigator.clipboard.writeText(text);
    } catch {
      const ta = document.createElement('textarea');
      ta.value = text;
      document.body.appendChild(ta);
      ta.select();
      document.execCommand('copy');
      document.body.removeChild(ta);
    }
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };
  return (
    <motion.button
      whileTap={{ scale: 0.96 }}
      onClick={copyToClipboard}
      className={`${s.copyButton} ${copied ? s.copyCopied : s.copyDefault}`}
    >
      <svg width={13} height={13} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round">
        <rect x="9" y="9" width="13" height="13" rx="2" ry="2" />
        <path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1" />
      </svg>
      {copied ? 'Copied!' : label}
    </motion.button>
  );
}

