// -- Share Analytics Dashboard -----------------------------------------------
function ShareAnalyticsDashboard({ links, isMobile }) {
  const [analytics, setAnalytics] = useState(null);
  const [selectedLink, setSelectedLink] = useState(null);

  const totalViews = links.reduce((sum, l) => sum + (l.view_count || 0), 0);
  const topLink = links.length > 0
    ? links.reduce((top, l) => (l.view_count || 0) > (top.view_count || 0) ? l : top, links[0])
    : null;

  useEffect(() => {
    if (!selectedLink) return;
    let cancelled = false;
    (async () => {
      try {
        const result = await api(`/share/analytics/${selectedLink}`);
        if (!cancelled && result) setAnalytics(result);
      } catch {
        // silent
      }
    })();
    return () => { cancelled = true; };
  }, [selectedLink]);

  const viewsData = analytics?.daily_views || [];

  return (
    <GlassPanel className={`${s.glassPanelMb} ${isMobile ? s.glassPadMobile : s.glassPadDesktop}`}>
      <SectionHeader
        title="Share Analytics"
        subtitle="Track engagement across your shared links"
      />

      {/* Summary tiles */}
      <div className={s.analyticsRow}>
        <div className={s.analyticsTile}>
          <div className={s.analyticsTileLabel}>Total Views</div>
          <div className={s.analyticsTileValue} style={{ color: C.blue }}>{totalViews}</div>
        </div>
        <div className={s.analyticsTile}>
          <div className={s.analyticsTileLabel}>Active Links</div>
          <div className={s.analyticsTileValue} style={{ color: C.green }}>{links.length}</div>
        </div>
        <div className={s.analyticsTile}>
          <div className={s.analyticsTileLabel}>Top Link</div>
          <div className={s.analyticsTileSmall}>
            {topLink ? (topLink.label || formatStrategyLabel(topLink.share_id)) : '--'}
          </div>
          <div className={s.analyticsTileSub}>
            {topLink ? `${topLink.view_count || 0} views` : ''}
          </div>
        </div>
      </div>

      {/* Per-link selector */}
      <div className={s.mb12}>
        <div className={s.analyticsLabel}>View Details For</div>
        <div className={s.analyticsLinkBtnRow}>
          {links.map(l => (
            <button
              key={l.share_id}
              onClick={() => setSelectedLink(l.share_id === selectedLink ? null : l.share_id)}
              className={`${s.analyticsLinkBtn} ${selectedLink === l.share_id ? s.analyticsLinkBtnActive : s.analyticsLinkBtnInactive}`}
            >
              {l.label || formatStrategyLabel(l.share_id).slice(0, 20)}
            </button>
          ))}
        </div>
      </div>

      {/* Views chart (simple bar chart) */}
      {selectedLink && viewsData.length > 0 && (
        <div className={s.analyticsChartWrap}>
          <div className={s.analyticsChartLabel}>Daily Views</div>
          <svg viewBox="0 0 400 80" className={s.analyticsChartSvg}>
            {(() => {
              const maxV = Math.max(...viewsData.map(d => d.views || 0), 1);
              const barW = Math.min(30, (380 / viewsData.length) - 4);
              return viewsData.map((d, i) => {
                const h = ((d.views || 0) / maxV) * 60;
                const x = 10 + i * (380 / viewsData.length);
                return (
                  <g key={i}>
                    <rect x={x} y={70 - h} width={barW} height={Math.max(h, 1)}
                      rx="3" fill={C.blue} opacity="0.8" />
                    <text x={x + barW / 2} y={78} fill={C.textSecondary}
                      fontSize="6" fontFamily={mono} textAnchor="middle">
                      {d.date?.slice(5) || ''}
                    </text>
                  </g>
                );
              });
            })()}
          </svg>
        </div>
      )}

      {selectedLink && viewsData.length === 0 && analytics && (
        <div className={s.analyticsNoData}>
          No view data available yet for this link.
        </div>
      )}
    </GlassPanel>
  );
}

// =============================================================================
// MAIN COMPONENT
// =============================================================================
export default function SharePortfolioPage() {
  usePageTitle('Share Portfolio');
  const isMobile = useIsMobile();

  // State
  const [shareType, setShareType] = useState('backtest');
  const [expiryDays, setExpiryDays] = useState(30);
  const [includeTrades, setIncludeTrades] = useState(true);
  const [selectedStrategy, setSelectedStrategy] = useState('');
  const [portfolioTitle, setPortfolioTitle] = useState('My Portfolio');
  const [strategies, setStrategies] = useState([]);
  const [myLinks, setMyLinks] = useState([]);
  const [creating, setCreating] = useState(false);
  const [successLink, setSuccessLink] = useState(null);
  const [previewData, setPreviewData] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(true);
  const abortRef = useRef(null);

  // -- Load strategies and existing links ------------------------------------
  const loadData = useCallback(async () => {
    setLoading(true);
    const controller = new AbortController();
    abortRef.current = controller;
    try {
      const [strats, links] = await Promise.all([
        api('/strategies', { signal: controller.signal }),
        api('/share/my-links', { signal: controller.signal }),
      ]);
      if (strats) {
        const list = strats.strategies || strats.data || strats || [];
        setStrategies(Array.isArray(list) ? list : []);
      }
      if (links) {
        setMyLinks(links.links || []);
      }
    } catch {
      // silent
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    loadData();
    return () => { abortRef.current?.abort(); };
  }, [loadData]);

  // -- Update preview when strategy changes ----------------------------------
  useEffect(() => {
    if (shareType === 'backtest' && selectedStrategy) {
      const strat = strategies.find(st => (st.key || st.name) === selectedStrategy);
      if (strat) {
        setPreviewData({
          strategy_key: selectedStrategy,
          metrics: {
            profit_factor: strat.profit_factor ?? strat.avg_pf,
            win_rate: strat.win_rate ?? strat.avg_win_rate,
            total_pnl: strat.total_pnl,
            total_trades: strat.total_trades ?? strat.count ?? strat.trades,
          },
        });
      }
    } else if (shareType === 'portfolio') {
      setPreviewData({
        title: portfolioTitle,
        strategies: strategies.filter(st => st.enabled !== false).slice(0, 10),
      });
    } else {
      setPreviewData(null);
    }
  }, [shareType, selectedStrategy, portfolioTitle, strategies]);

  // -- Create share link -----------------------------------------------------
  const handleCreate = async () => {
    setCreating(true);
    setError(null);
    setSuccessLink(null);

    try {
      let result;
      if (shareType === 'backtest') {
        if (!selectedStrategy) {
          setError('Please select a strategy to share.');
          setCreating(false);
          return;
        }
        result = await apiPost('/share/backtest', {
          strategy_key: selectedStrategy,
          region: 'us',
          timeframe: 'all',
          include_trades: includeTrades,
        });
      } else {
        result = await apiPost('/share/portfolio', {
          title: portfolioTitle,
          strategies: [],
          performance_summary: {},
        });
      }

      if (result?.ok) {
        const fullUrl = `${window.location.origin}/shared/${result.share_id}`;
        setSuccessLink({
          share_id: result.share_id,
          url: fullUrl,
          type: result.type,
          expires_at: result.expires_at,
        });
        const links = await api('/share/my-links');
        if (links) setMyLinks(links.links || []);
      } else {
        setError('Failed to create share link. Please try again.');
      }
    } catch (e) {
      setError(e?.message || 'Network error creating share link.');
    }
    setCreating(false);
  };

  // -- Delete (revoke) share link --------------------------------------------
  const handleDelete = async (shareId) => {
    const result = await apiDelete(`/share/${shareId}`);
    if (result?.ok) {
      setMyLinks(prev => prev.map(l =>
        l.share_id === shareId ? { ...l, is_active: 0 } : l
      ));
    }
  };

  // -- Social share helpers --------------------------------------------------
  const socialShare = (platform, url, title) => {
    const encodedUrl = encodeURIComponent(url);
    const encodedTitle = encodeURIComponent(title);
    const urls = {
      twitter: `https://twitter.com/intent/tweet?text=${encodedTitle}&url=${encodedUrl}`,
      linkedin: `https://www.linkedin.com/sharing/share-offsite/?url=${encodedUrl}`,
    };
    window.open(urls[platform], '_blank', 'noopener,noreferrer');
  };

  // -- Active / expired counts -----------------------------------------------
  const activeLinks = myLinks.filter(l => l.is_active && (!l.expires_at || new Date(l.expires_at) > new Date()));
  const expiredLinks = myLinks.filter(l => !l.is_active || (l.expires_at && new Date(l.expires_at) <= new Date()));

  const isCreateDisabled = creating || (shareType === 'backtest' && !selectedStrategy);

  // =========================================================================
  return (
    <AnimatedPage>
      <div className={`${s.page} ${isMobile ? s.pagePadMobile : s.pagePadDesktop}`}>
        {/* -- Page Header -------------------------------------------------- */}
        <div className={s.pageHeaderRow}>
          <h1 className={`${s.pageTitle} ${isMobile ? s.pageTitleMobile : s.pageTitleDesktop}`}>
            Share Portfolio
          </h1>
          <span className={s.activeLinkBadge}>
            {activeLinks.length} active link{activeLinks.length !== 1 ? 's' : ''}
          </span>
        </div>
        <p className={s.pageSubtitle}>
          Create shareable links for your backtest results or portfolio snapshots. Links contain a frozen snapshot -- not live data.
        </p>

        {/* -- Create Share Section ----------------------------------------- */}
        <GlassPanel className={`${s.glassPanelMb} ${isMobile ? s.glassPadMobile : s.glassPadDesktop}`}>
          <SectionHeader
            title="Create Share Link"
            subtitle="Choose what to share and configure visibility"
          />

          {/* Share type selector */}
          <div className={s.shareTypeRow}>
            <ShareTypeTab
              active={shareType === 'backtest'}
              label="Backtest Result"
              onClick={() => setShareType('backtest')}
              icon={
                <svg width={16} height={16} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round">
                  <polyline points="22 12 18 12 15 21 9 3 6 12 2 12" />
                </svg>
              }
            />
            <ShareTypeTab
              active={shareType === 'portfolio'}
              label="Portfolio Snapshot"
              onClick={() => setShareType('portfolio')}
              icon={
                <svg width={16} height={16} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round">
                  <path d="M21 16V8a2 2 0 00-1-1.73l-7-4a2 2 0 00-2 0l-7 4A2 2 0 002 8v8a2 2 0 001 1.73l7 4a2 2 0 002 0l7-4A2 2 0 0021 16z" />
                </svg>
              }
            />
          </div>

          {/* Backtest options */}
          {shareType === 'backtest' && (
            <div className={s.optionSectionMb}>
              <div className={s.selectStrategyLabel}>Select Strategy</div>
              <StrategySelector
                strategies={strategies}
                selected={selectedStrategy}
                onSelect={setSelectedStrategy}
                isMobile={isMobile}
              />
              <div className={s.checkboxMt}>
                <Checkbox
                  checked={includeTrades}
                  onChange={(e) => setIncludeTrades(e.target.checked)}
                  label="Include trade history"
                  sublabel="Shows equity curve and recent trades in the shared view"
                />
              </div>
            </div>
          )}

          {/* Portfolio options */}
          {shareType === 'portfolio' && (
            <div className={s.optionSectionMb}>
              <div className={s.portfolioTitleLabel}>Portfolio Title</div>
              <input
                type="text"
                value={portfolioTitle}
                onChange={e => setPortfolioTitle(e.target.value)}
                placeholder="My Trading Portfolio"
                className={s.portfolioTitleInput}
              />
              <p className={s.portfolioTitleHint}>
                Your current enabled strategies and aggregate performance will be included automatically.
              </p>
            </div>
          )}

          {/* Expiry */}
          <div className={s.optionSectionMb}>
            <div className={s.expiryLabel}>Link Expiry</div>
            <ExpirySelector value={expiryDays} onChange={setExpiryDays} />
          </div>

          {/* Create button */}
          <motion.button
            whileTap={{ scale: 0.97 }}
            onClick={handleCreate}
            disabled={isCreateDisabled}
            className={`${s.createButton} ${isCreateDisabled ? s.createDisabled : s.createEnabled}`}
          >
            {creating ? (
              <>
                <div className={s.createSpinner} />
                Creating...
              </>
            ) : (
              <>
                <svg width={16} height={16} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round">
                  <path d="M10 13a5 5 0 007.54.54l3-3a5 5 0 00-7.07-7.07l-1.72 1.71" />
                  <path d="M14 11a5 5 0 00-7.54-.54l-3 3a5 5 0 007.07 7.07l1.71-1.71" />
                </svg>
                Generate Share Link
              </>
            )}
          </motion.button>

          {/* Error */}
          {error && (
            <motion.div
              initial={{ opacity: 0, y: -4 }}
              animate={{ opacity: 1, y: 0 }}
              className={s.errorBanner}
            >
              {error}
            </motion.div>
          )}

          {/* Success */}
          <AnimatePresence>
            {successLink && (
              <motion.div
                initial={{ opacity: 0, y: -8 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -8 }}
                className={s.successBanner}
              >
                <div className={s.successHeader}>
                  <svg width={18} height={18} viewBox="0 0 24 24" fill="none" stroke={C.green} strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round">
                    <path d="M22 11.08V12a10 10 0 11-5.93-9.14" />
                    <polyline points="22 4 12 14.01 9 11.01" />
                  </svg>
                  <span className={s.successLabel}>Share link created!</span>
                </div>

                <div className={s.successLinkRow}>
                  <span className={s.successLinkText}>{successLink.url}</span>
                  <CopyButton text={successLink.url} label="Copy" />
                </div>

                <div className={s.socialButtonsRow}>
                  <motion.button
                    whileTap={{ scale: 0.96 }}
                    onClick={() => socialShare('twitter', successLink.url, `Check out my ${successLink.type} results on Aura Alpha`)}
                    className={s.socialButton}
                    style={{ color: '#1DA1F2' }}
                  >
                    <svg width={14} height={14} viewBox="0 0 24 24" fill="currentColor">
                      <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231zm-1.161 17.52h1.833L7.084 4.126H5.117z" />
                    </svg>
                    Share on X
                  </motion.button>
                  <motion.button
                    whileTap={{ scale: 0.96 }}
                    onClick={() => socialShare('linkedin', successLink.url, `Aura Alpha Trading Results`)}
                    className={s.socialButton}
                    style={{ color: '#0A66C2' }}
                  >
                    <svg width={14} height={14} viewBox="0 0 24 24" fill="currentColor">
                      <path d="M20.447 20.452h-3.554v-5.569c0-1.328-.027-3.037-1.852-3.037-1.853 0-2.136 1.445-2.136 2.939v5.667H9.351V9h3.414v1.561h.046c.477-.9 1.637-1.85 3.37-1.85 3.601 0 4.267 2.37 4.267 5.455v6.286zM5.337 7.433a2.062 2.062 0 01-2.063-2.065 2.064 2.064 0 112.063 2.065zm1.782 13.019H3.555V9h3.564v11.452zM22.225 0H1.771C.792 0 0 .774 0 1.729v20.542C0 23.227.792 24 1.771 24h20.451C23.2 24 24 23.227 24 22.271V1.729C24 .774 23.2 0 22.222 0h.003z" />
                    </svg>
                    LinkedIn
                  </motion.button>
                </div>

                <div className={s.successExpiry}>
                  Expires: {successLink.expires_at ? fmtDate(successLink.expires_at) : 'Never'}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </GlassPanel>

        {/* -- Preview Section ---------------------------------------------- */}
        {previewData && (
          <div className={s.previewSectionMb}>
            <PreviewCard type={shareType} shareUrl={successLink?.url} data={previewData} />
          </div>
        )}

        {/* -- Active Links Section ----------------------------------------- */}
        <GlassPanel className={s.glassPanelMb}>
          <div className={s.linksListHeader}>
            <SectionHeader
              title="Your Shared Links"
              subtitle={`${activeLinks.length} active, ${expiredLinks.length} expired/revoked`}
            />
          </div>

          {loading ? (
            <div className={s.linksLoading}>
              <motion.div
                animate={{ opacity: [0.4, 1, 0.4] }}
                transition={{ duration: 1.5, repeat: Infinity }}
              >
                Loading links...
              </motion.div>
            </div>
          ) : myLinks.length === 0 ? (
            <div className={s.linksEmpty}>
              <svg width={40} height={40} viewBox="0 0 24 24" fill="none" stroke={C.border} strokeWidth={1.5} strokeLinecap="round" strokeLinejoin="round" style={{ marginBottom: 12, opacity: 0.5 }}>
                <path d="M10 13a5 5 0 007.54.54l3-3a5 5 0 00-7.07-7.07l-1.72 1.71" />
                <path d="M14 11a5 5 0 00-7.54-.54l-3 3a5 5 0 007.07 7.07l1.71-1.71" />
              </svg>
              <div>No shared links yet</div>
              <div className={s.linksEmptySub}>Create your first share link above</div>
            </div>
          ) : (
            <motion.div
              variants={staggerContainer}
              initial="initial"
              animate="animate"
            >
              {myLinks.map(link => (
                <ActiveShareRow
                  key={link.share_id}
                  link={link}
                  onDelete={handleDelete}
                  isMobile={isMobile}
                />
              ))}
            </motion.div>
          )}
        </GlassPanel>

        {/* -- Embed Code Section ------------------------------------------ */}
        {successLink && (
          <EmbedCodeSection shareId={successLink.share_id} isMobile={isMobile} />
        )}

        {/* -- Social Preview Card ----------------------------------------- */}
        {successLink && (
          <SocialPreviewCard
            shareUrl={successLink.url}
            shareType={successLink.type}
            strategyKey={selectedStrategy}
            title={shareType === 'portfolio' ? portfolioTitle : formatStrategyLabel(selectedStrategy)}
            isMobile={isMobile}
          />
        )}

        {/* -- Share Analytics Dashboard ----------------------------------- */}
        {activeLinks.length > 0 && (
          <ShareAnalyticsDashboard links={activeLinks} isMobile={isMobile} />
        )}

        {/* -- How It Works ------------------------------------------------- */}
        <GlassPanel className={isMobile ? s.glassPadMobile : s.glassPadDesktop}>
          <SectionHeader title="How Sharing Works" />
          <div className={`${s.howGrid} ${isMobile ? s.howGridMobile : s.howGridDesktop}`}>
            {[
              { step: '1', title: 'Create a Snapshot', desc: 'Choose a backtest result or your full portfolio. The data is frozen at creation time.', color: C.blue },
              { step: '2', title: 'Share the Link', desc: 'Copy the unique URL and share it on social media, in messages, or embed it anywhere.', color: C.green },
              { step: '3', title: 'Track & Manage', desc: 'See how many views your links get. Revoke access anytime with one click.', color: C.purple },
            ].map(item => (
              <div key={item.step} className={s.howCard}>
                <div className={s.howStepBadge} style={{ background: `${item.color}18`, color: item.color }}>
                  {item.step}
                </div>
                <div className={s.howStepTitle}>{item.title}</div>
                <div className={s.howStepDesc}>{item.desc}</div>
              </div>
            ))}
          </div>

          <div className={s.howDisclaimer}>
            Shared links contain a point-in-time snapshot. They do not update with live data. This protects your current positions and strategy configuration from being exposed.
          </div>
        </GlassPanel>
      </div>
    </AnimatedPage>
  );
}
